# Invariants & contracts
  @contract  rehydrate on a groups invalidate (undo rewind); own assign echoes lack it, ignored  @ 638

# Shapes
  @shape  group = { rect, events = { [vuid]=groupEvt }, nextVuid, instances = { [instId]=instance } }  @ 3
  @shape  instance = { anchor = { ppq, chan, [laneDelta] }, assigns, adds, deletes }  -- pure data, persisted verbatim  @ 4
  @shape  proj[groupId][instId][vuid] = { uuid, groupEvt=clone, evt=liveEvt }  -- module-level, runtime; only `uuid` serialised, persisted as `uuids[groupId][instId][vuid]`  @ 5
  @shape  persisted groups = { groups = groups, uuids = { [groupId]={ [instId]={ [vuid]=uuid } } } }  @ 6

